    46→                                {APP_NAV_LINKS.map((link) => {
    47→                                    const isActive = pathname === link.href || pathname?.startsWith(link.href + "/");
    48→                                    return (
    49→                                        <Link
    50→                                            key={link.href}
    51→                                            href={link.href}
    52→                                            className={cn(
    53→                                                "relative text-sm font-medium uppercase tracking-widest transition-colors duration-200 cursor-pointer pb-[1.19rem] pt-[1.19rem]",
    54→                                                isActive
    55→                                                    ? "text-[#F75105]"
    56→                                                    : "text-[#A1A1AA] hover:text-[#FAFAFA]"
    57→                                            )}
    58→                                        >
    59→                                            {link.label}
    60→                                            {isActive && (
    61→                                                <span className="absolute bottom-0 left-0 right-0 h-[2px] bg-[#F75105]" />
    62→                                            )}
    63→                                        </Link>
    64→                                    );
    65→                                })}
    66→                            </nav>
    67→                        </>
    68→                    )}
    69→                </div>
    70→
    71→                {/* Right: Controls */}
    72→                <div className="flex items-center gap-6">
    73→                    {variant === "public" ? (
    74→                        <>
    75→                            <nav className="hidden md:flex items-center gap-8">
    76→                                {["Manifesto", "Technologie", "Sécurité"].map((item) => (
    77→                                    <Link
    78→                                        key={item}
    79→                                        href={`#${item.toLowerCase()}`}
    80→                                        className="text-xs font-mono font-medium uppercase tracking-widest text-[#94A3B8] hover:text-white transition-colors duration-200 cursor-pointer"
    81→                                    >
    82→                                        {item}
    83→                                    </Link>
    84→                                ))}
    85→                            </nav>
    86→                            <Link href="/capture" className="cursor-pointer">
    87→                                <button className="group flex items-center gap-2 bg-[#F75105] hover:bg-[#F75105]/90 text-white px-5 py-2 rounded-full text-xs font-bold uppercase tracking-wider transition-all duration-300 shadow-[0_0_20px_rgba(247,81,5,0.2)] hover:shadow-[0_0_30px_rgba(247,81,5,0.4)] hover:scale-105 active:scale-95 cursor-pointer">
    88→                                    Commencer
    89→                                    <ArrowRight className="w-3 h-3 group-hover:translate-x-1 transition-transform duration-200" />
    90→                                </button>
    91→                            </Link>
    92→                        </>
    93→                    ) : (
    94→                        <div className="flex items-center gap-3">
    95→                            <LanguageSelector />
    96→                            <div className="h-4 w-[1px] bg-[--color-border-default] mx-2" />
    97→                            <UserNav />
    98→                        </div>
    99→                    )}
   100→                </div>
   101→            </div>
   102→        </header>
   103→    );
   104→}
